import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("Ascension-Rule-IdentitySelector-Amita");
  logger.debug("Ascension-Rule-IdentitySelector-Amita Starting");


  String domain = identity.getStringAttribute("domain");
  Map result = null;
  boolean flag = false;


  if(Util.nullSafeCaseInsensitiveEq(domain , "AMITA") ){

    // Check identity has PersenceHealth account

    IdentityService idSvc = new IdentityService(context);
    Application application = context.getObjectByName(Application.class, "AD-PRESENCEHEALTH");
    if(application != null){

      List links = idSvc.getLinks(identity,application);


      if(!Util.isEmpty(links)){

        result = getBundleCriteria(roleName);

        if(!Util.isEmpty(result)){

          String inputJobCode =  Util.isNotNullOrEmpty(result.get("Job"))?result.get("Job"):"";  
          String inputLocation =  Util.isNotNullOrEmpty(result.get("Loc"))?result.get("Loc"):""; 
          String inputMinDepartmentNumber =  Util.isNotNullOrEmpty(result.get("DeptMin"))?result.get("DeptMin"):""; 
          String inputMaxDepartmentNumber =  Util.isNotNullOrEmpty(result.get("DeptMax"))?result.get("DeptMax"):""; 

          flag =  isEligibleAmitaBundleAssignment(identity.getName(), inputJobCode ,inputLocation ,inputMinDepartmentNumber ,inputMaxDepartmentNumber );
        }
      }
     //comment decache //context.decache(application);
    }
    
  }

  
  logger.debug("Ascension-Rule-IdentitySelector-Amita Ending");
  return flag ;
